# --- tensor_field.py ---
"""
张量场 / Tensor Field
基于论文 "Interactive Procedural Street Modeling" (Chen et al., SIGGRAPH 2008)
使用 2×2 对称无迹矩阵表示，RBF 加权组合设计元素，支持旋转场、笔刷、Laplacian 平滑。
"""

import math


BASIS_GRID = "grid"
BASIS_RADIAL = "radial"
BASIS_BLEND = "blend"
BASIS_BOUNDARY = "boundary"
BASIS_BOUNDARY_BLEND = "boundary_blend"
BASIS_HEIGHT = "height"
BASIS_HEIGHT_BLEND = "height_blend"

# RBF 衰减常数：论文 T(p) = Σ exp(-d||p-pi||²) Ti(p)
# d 越大衰减越快，用 1/decay² 使距离 decay 时权重≈exp(-1)
_DEFAULT_DECAY = 150


def _normalize(ux, uy):
    """归一化向量"""
    L = math.sqrt(ux * ux + uy * uy) or 1e-10
    return ux / L, uy / L


def _orthogonal(ux, uy):
    """返回与 (ux, uy) 垂直的单位向量"""
    return _normalize(-uy, ux)


# ---------------------------------------------------------------------------
# 论文式张量：2×2 对称无迹矩阵 T = R * [[cos 2θ, sin 2θ], [sin 2θ, -cos 2θ]]
# 存储为 (a, b)，矩阵为 [[a, b], [b, -a]]，其中 a=R*cos(2θ), b=R*sin(2θ)
# ---------------------------------------------------------------------------


def _tensor_from_direction(ux, uy, scale=1.0):
    """
    论文 Eq.(1) Grid/Regular 基底：方向 (ux, uy)，l=||(ux,uy)||, θ=atan2(uy,ux)
    T = l * [[cos 2θ, sin 2θ], [sin 2θ, -cos 2θ]]
    返回 (a, b) 即矩阵 [[a,b],[b,-a]]
    """
    l = math.sqrt(ux * ux + uy * uy) or 1e-10
    theta = math.atan2(uy, ux)
    c2 = math.cos(2 * theta)
    s2 = math.sin(2 * theta)
    R = l * scale
    return R * c2, R * s2


def _tensor_radial(x, y):
    """
    论文 Eq.(2) Radial 基底：x=xp-x0, y=yp-y0
    T = [[y²-x², -2xy], [-2xy, -(y²-x²)]]
    返回 (a, b)，矩阵 [[a,b],[b,-a]]，a=y²-x², b=-2xy
    """
    xx = x * x
    yy = y * y
    xy = x * y
    a = yy - xx
    b = -2 * xy
    return a, b


def _tensor_height(gx, gy):
    """
    论文 Heightfield：minor eigenvector 匹配梯度，θ = atan2(gy,gx) + π/2
    R = ||∇H||, T = R * [[cos 2θ, sin 2θ], [sin 2θ, -cos 2θ]]
    """
    R = math.sqrt(gx * gx + gy * gy)
    if R < 1e-10:
        return None
    theta = math.atan2(gy, gx) + math.pi / 2
    c2 = math.cos(2 * theta)
    s2 = math.sin(2 * theta)
    return R * c2, R * s2


def _tensor_add(ta, tb, wa=1.0, wb=1.0):
    """矩阵加权相加：T = wa*Ta + wb*Tb，返回 (a, b)"""
    if ta is None:
        return (wb * tb[0], wb * tb[1]) if tb else None
    if tb is None:
        return (wa * ta[0], wa * ta[1])
    return wa * ta[0] + wb * tb[0], wa * ta[1] + wb * tb[1]


def _tensor_to_eigenvectors(a, b):
    """
    从对称无迹矩阵 [[a,b],[b,-a]] 提取主/副特征向量。
    特征值 λ = ±sqrt(a²+b²)，主特征向量对应 λ=+sqrt(a²+b²)。
    返回 (ux, uy, vx, vy) 单位向量，退化时返回 None。
    """
    norm_sq = a * a + b * b
    if norm_sq < 1e-20:
        return None
    lam = math.sqrt(norm_sq)
    # 主特征向量 (b, lam-a)；当 b≈0 时 (b, lam-a)=(0,0)，需特殊处理
    if abs(b) < 1e-10:
        if a > 0:
            return 1.0, 0.0, 0.0, 1.0
        return 0.0, 1.0, -1.0, 0.0
    ux, uy = b, lam - a
    L = math.sqrt(ux * ux + uy * uy) or 1e-10
    ux, uy = ux / L, uy / L
    vx, vy = _orthogonal(ux, uy)
    return ux, uy, vx, vy


def _apply_rotation(ux, uy, vx, vy, r1=0, r2=0, r3=0):
    """
    论文 5.3 旋转场：R1 同时旋转主副（反向），R2 仅主，R3 仅副。
    角度单位为弧度。
    """
    if abs(r1) < 1e-10 and abs(r2) < 1e-10 and abs(r3) < 1e-10:
        return ux, uy, vx, vy
    c1, s1 = math.cos(r1), math.sin(r1)
    c2, s2 = math.cos(r2), math.sin(r2)
    c3, s3 = math.cos(r3), math.sin(r3)
    # R1: 主 +r1, 副 -r1
    ux2 = ux * c1 - uy * s1
    uy2 = ux * s1 + uy * c1
    vx2 = vx * c1 + vy * s1
    vy2 = -vx * s1 + vy * c1
    # R2: 仅主
    ux2, uy2 = ux2 * c2 - uy2 * s2, ux2 * s2 + uy2 * c2
    # R3: 仅副
    vx2, vy2 = vx2 * c3 - vy2 * s3, vx2 * s3 + vy2 * c3
    return ux2, uy2, vx2, vy2


def _rbf_weight(dist_sq, decay):
    """RBF 权重 exp(-d * dist²)，d = 1/decay²"""
    d = 1.0 / (decay * decay) if decay > 0 else 0.01
    return math.exp(-d * dist_sq)


def _rbf_weight_fast(dist_sq, d_inv):
    """RBF 权重，d_inv 已预计算"""
    return math.exp(-d_inv * dist_sq)


def _normalize_centers(centers):
    """centers: list of (x,y) or single (x,y) -> list of (x,y)"""
    if not centers:
        return [(0, 0)]
    if isinstance(centers[0], (int, float)):
        return [tuple(centers)]
    return list(centers)


def brush_strokes_to_elements(brush_strokes, brush_decay=80):
    """
    论文 5.2 笔刷：将用户绘制的曲线转为设计元素。
    brush_strokes: list of [(x,y), ...] 每条笔刷折线
    返回设计元素列表
    """
    elements = []
    if not brush_strokes:
        return elements
    brush_d_inv = 1.0 / (brush_decay * brush_decay) if brush_decay > 0 else 0.01
    for stroke in brush_strokes:
        if len(stroke) < 2:
            continue
        sampled = sample_curve(stroke, num_samples=60)
        n = len(sampled)
        for i in range(n):
            x, y = sampled[i][0], sampled[i][1]
            i0, i1 = max(0, i - 1), min(n - 1, i + 1)
            dx = sampled[i1][0] - sampled[i0][0]
            dy = sampled[i1][1] - sampled[i0][1]
            L = math.sqrt(dx * dx + dy * dy) or 1e-10
            tx, ty = dx / L, dy / L
            t = _tensor_from_direction(tx, ty)
            elements.append({"type": "brush", "pos": (x, y), "tensor_const": t, "weight": 1.0, "rbf_decay": brush_decay, "rbf_d_inv": brush_d_inv})
    return elements


def _build_design_elements(basis, centers, blend_factor,
                          boundary, boundary_decay, boundary_blend,
                          height_gradient_fn, height_blend,
                          brush_strokes=None, brush_decay=80):
    """
    从当前 UI 参数构建设计元素列表。
    centers: list of (x,y) 支持多个张量中心
    brush_strokes: list of [(x,y),...] 笔刷折线，论文 5.2
    每个元素: {"type": str, "pos": (x,y), "tensor_fn": (x,y)->(a,b) or None, "tensor_const": (a,b), "weight": float, "rbf_decay": float}
    """
    elements = []
    decay = boundary_decay if boundary_decay > 0 else _DEFAULT_DECAY
    decay_sq_inv = 1.0 / (decay * decay) if decay > 0 else 0.01
    centers = _normalize_centers(centers)
    cx0, cy0 = centers[0]  # 首个中心用于 grid/fallback

    if basis == BASIS_GRID:
        t = _tensor_from_direction(1.0, 0.0)
        elements.append({"type": "grid", "pos": (cx0, cy0), "tensor_const": t, "weight": 1.0, "rbf_decay": 0})

    elif basis == BASIS_RADIAL:
        # 径向基底：副特征向量指向中心，所有副超流线汇聚于中心导致团状。
        # 混入少量网格分量（约 18%）打破完美径向，使街道分散。
        t_grid = _tensor_from_direction(1.0, 0.0)
        elements.append({"type": "grid", "pos": (cx0, cy0), "tensor_const": t_grid, "weight": 0.18, "rbf_decay": 0})
        for cx, cy in centers:
            def radial_fn(px, py, cxx=cx, cyy=cy):
                dx = px - cxx
                dy = py - cyy
                return _tensor_radial(dx, dy)
            elements.append({"type": "radial", "pos": (cx, cy), "tensor_fn": radial_fn, "weight": 1.0, "rbf_decay": decay, "rbf_d_inv": decay_sq_inv})

    elif basis == BASIS_BLEND:
        bf = max(0, min(1, blend_factor))
        t_grid = _tensor_from_direction(1.0, 0.0)
        elements.append({"type": "grid", "pos": (cx0, cy0), "tensor_const": t_grid, "weight": 1.0 - bf, "rbf_decay": 0})
        for cx, cy in centers:
            def radial_fn(px, py, cxx=cx, cyy=cy):
                dx = px - cxx
                dy = py - cyy
                return _tensor_radial(dx, dy)
            elements.append({"type": "radial", "pos": (cx, cy), "tensor_fn": radial_fn, "weight": bf, "rbf_decay": decay, "rbf_d_inv": decay_sq_inv})

    elif basis == BASIS_BOUNDARY:
        if boundary:
            for bx, by, tx, ty in boundary:
                t = _tensor_from_direction(tx, ty)
                elements.append({"type": "boundary", "pos": (bx, by), "tensor_const": t, "weight": 1.0, "rbf_decay": decay, "rbf_d_inv": decay_sq_inv})
        if not elements:
            t = _tensor_from_direction(1.0, 0.0)
            elements.append({"type": "grid", "pos": (cx0, cy0), "tensor_const": t, "weight": 1.0, "rbf_decay": 0})

    elif basis == BASIS_BOUNDARY_BLEND:
        bb = max(0, min(1, boundary_blend))
        t_grid = _tensor_from_direction(1.0, 0.0)
        elements.append({"type": "grid", "pos": (cx0, cy0), "tensor_const": t_grid, "weight": (1.0 - bb), "rbf_decay": 0})
        if boundary:
            for bx, by, tx, ty in boundary:
                t = _tensor_from_direction(tx, ty)
                elements.append({"type": "boundary", "pos": (bx, by), "tensor_const": t, "weight": bb, "rbf_decay": decay, "rbf_d_inv": decay_sq_inv})

    elif basis == BASIS_HEIGHT:
        if height_gradient_fn:
            def height_fn(px, py):
                gx, gy = height_gradient_fn(px, py)
                return _tensor_height(gx, gy)
            elements.append({"type": "height", "pos": (cx0, cy0), "tensor_fn": height_fn, "weight": 1.0, "rbf_decay": 0})
        if not elements:
            t = _tensor_from_direction(1.0, 0.0)
            elements.append({"type": "grid", "pos": (cx0, cy0), "tensor_const": t, "weight": 1.0, "rbf_decay": 0})

    elif basis == BASIS_HEIGHT_BLEND:
        hb = max(0, min(1, height_blend))
        t_grid = _tensor_from_direction(1.0, 0.0)
        elements.append({"type": "grid", "pos": (cx0, cy0), "tensor_const": t_grid, "weight": (1.0 - hb), "rbf_decay": 0})
        if height_gradient_fn:
            def height_fn(px, py):
                gx, gy = height_gradient_fn(px, py)
                return _tensor_height(gx, gy)
            elements.append({"type": "height", "pos": (cx0, cy0), "tensor_fn": height_fn, "weight": hb, "rbf_decay": 0})

    else:
        t = _tensor_from_direction(1.0, 0.0)
        elements.append({"type": "grid", "pos": (cx0, cy0), "tensor_const": t, "weight": 1.0, "rbf_decay": 0})

    # 论文 5.2 笔刷：叠加笔刷设计元素
    if brush_strokes:
        elements.extend(brush_strokes_to_elements(brush_strokes, brush_decay))

    return elements


def _compute_tensor_at(x, y, elements):
    """
    论文 Eq.(3) 组合：T(p) = Σ exp(-d||p-pi||²) * weight_i * Ti(p)
    返回 (a, b) 或 None（全退化）
    """
    total_a, total_b = 0.0, 0.0
    total_w = 0.0

    for el in elements:
        px, py = el["pos"]
        dx = x - px
        dy = y - py
        dist_sq = dx * dx + dy * dy
        rbf = 1.0 if el["rbf_decay"] <= 0 else _rbf_weight_fast(dist_sq, el["rbf_d_inv"])
        w = el["weight"] * rbf
        if w < 1e-6:
            continue

        if "tensor_const" in el:
            ta, tb = el["tensor_const"]
        else:
            t = el["tensor_fn"](x, y)
            if t is None:
                continue
            ta, tb = t

        total_a += w * ta
        total_b += w * tb
        total_w += w

    if total_w < 1e-10:
        return None
    # 论文式直接求和，不归一化（特征向量与缩放无关）
    return total_a, total_b


def _perlin_rotation_at(x, y, scale, strength, which="r1"):
    """论文 5.3：Perlin 噪声生成旋转场，范围 [-π/2, π/2] * strength"""
    n = perlin_noise(x, y, scale=scale)
    angle = n * strength * (math.pi / 2)
    return angle


def create_tensor_field_fn(basis, centers, blend_factor=0.5,
                           boundary=None, boundary_decay=150, boundary_blend=0.5,
                           height_gradient_fn=None, height_blend=0.5,
                           brush_strokes=None, brush_decay=80,
                           perlin_rotation_scale=0.005, perlin_rotation_strength=0,
                           perlin_r1=True, perlin_r2=False, perlin_r3=False):
    """
    创建带缓存设计元素的张量场函数，避免每点重建 elements。
    返回 (x, y) -> (ux, uy, vx, vy)
    """
    elements = _build_design_elements(
        basis, centers, blend_factor,
        boundary, boundary_decay, boundary_blend,
        height_gradient_fn, height_blend,
        brush_strokes=brush_strokes, brush_decay=brush_decay,
    )
    half_pi = math.pi / 2
    pscale = perlin_rotation_scale
    pstr = perlin_rotation_strength

    def fn(x, y):
        t = _compute_tensor_at(x, y, elements)
        if t is None:
            return 1.0, 0.0, 0.0, 1.0
        uv = _tensor_to_eigenvectors(t[0], t[1])
        if uv is None:
            return 1.0, 0.0, 0.0, 1.0
        ux, uy, vx, vy = uv
        pr1 = pr2 = pr3 = 0.0
        if pstr > 0:
            if perlin_r1:
                pr1 = perlin_noise(x, y, scale=pscale) * pstr * half_pi
            if perlin_r2:
                pr2 = perlin_noise(x, y + 1000, scale=pscale) * pstr * half_pi
            if perlin_r3:
                pr3 = perlin_noise(x + 500, y, scale=pscale) * pstr * half_pi
        ux, uy, vx, vy = _apply_rotation(ux, uy, vx, vy, pr1, pr2, pr3)
        return ux, uy, vx, vy

    return fn


def tensor_field_at(x, y, basis, centers, blend_factor=0.5,
                    boundary=None, boundary_decay=150, boundary_blend=0.5,
                    height_gradient_fn=None, height_blend=0.5,
                    r1=0, r2=0, r3=0,
                    brush_strokes=None, brush_decay=80,
                    perlin_rotation_scale=0.005, perlin_rotation_strength=0,
                    perlin_r1=True, perlin_r2=False, perlin_r3=False):
    """
    在 (x, y) 处计算张量场，返回两组互相垂直的单位方向。
    采用论文逻辑：2×2 对称无迹矩阵 + RBF 组合 + 可选旋转场 + 笔刷 + Perlin 噪声。

    Args:
        brush_strokes: list of [(x,y),...] 笔刷折线
        perlin_rotation_scale: Perlin 空间尺度
        perlin_rotation_strength: 旋转强度 [0,1]，0 表示关闭
        perlin_r1/r2/r3: 是否对 R1/R2/R3 应用 Perlin
    """
    elements = _build_design_elements(
        basis, centers, blend_factor,
        boundary, boundary_decay, boundary_blend,
        height_gradient_fn, height_blend,
        brush_strokes=brush_strokes, brush_decay=brush_decay,
    )
    t = _compute_tensor_at(x, y, elements)
    if t is None:
        return 1.0, 0.0, 0.0, 1.0
    uv = _tensor_to_eigenvectors(t[0], t[1])
    if uv is None:
        return 1.0, 0.0, 0.0, 1.0
    ux, uy, vx, vy = uv

    # 论文 5.3 Perlin 旋转
    pr1, pr2, pr3 = r1, r2, r3
    if perlin_rotation_strength > 0:
        if perlin_r1:
            pr1 += _perlin_rotation_at(x, y, perlin_rotation_scale, perlin_rotation_strength, "r1")
        if perlin_r2:
            pr2 += _perlin_rotation_at(x, y, perlin_rotation_scale, perlin_rotation_strength, "r2")
        if perlin_r3:
            pr3 += _perlin_rotation_at(x, y, perlin_rotation_scale, perlin_rotation_strength, "r3")
    ux, uy, vx, vy = _apply_rotation(ux, uy, vx, vy, pr1, pr2, pr3)
    return ux, uy, vx, vy


def laplacian_smooth_tensor_grid(grid_a, grid_b, nx, ny, iterations=3):
    """
    论文 5.2：对网格上的张量场做 Laplacian 平滑。
    双缓冲避免每轮深拷贝，*0.25 替代 /4
    """
    if iterations <= 0:
        return grid_a, grid_b
    # 双缓冲
    buf_a = [row[:] for row in grid_a]
    buf_b = [row[:] for row in grid_b]
    src_a, src_b = grid_a, grid_b
    dst_a, dst_b = buf_a, buf_b
    q = 0.25
    for _ in range(iterations):
        for j in range(1, ny - 1):
            for i in range(1, nx - 1):
                dst_a[j][i] = (src_a[j-1][i] + src_a[j+1][i] + src_a[j][i-1] + src_a[j][i+1]) * q
                dst_b[j][i] = (src_b[j-1][i] + src_b[j+1][i] + src_b[j][i-1] + src_b[j][i+1]) * q
        src_a, dst_a = dst_a, src_a
        src_b, dst_b = dst_b, src_b
    return src_a, src_b


def create_smoothed_tensor_fn(tensor_fn, site_width, site_height, grid_step=20, smooth_iterations=3):
    """
    创建经过 Laplacian 平滑的张量场采样函数。
    在网格上采样、平滑、双线性插值。
    """
    nx = max(2, int(site_width / grid_step) + 1)
    ny = max(2, int(site_height / grid_step) + 1)
    inv_nx = 1.0 / max(nx - 1, 1)
    inv_ny = 1.0 / max(ny - 1, 1)
    grid_a = [[0.0] * nx for _ in range(ny)]
    grid_b = [[0.0] * nx for _ in range(ny)]
    for j in range(ny):
        for i in range(nx):
            x = i * inv_nx * site_width
            y = j * inv_ny * site_height
            ux, uy, vx, vy = tensor_fn(x, y)
            theta = math.atan2(uy, ux)
            theta2 = 2 * theta
            grid_a[j][i] = math.cos(theta2)
            grid_b[j][i] = math.sin(theta2)
    grid_a, grid_b = laplacian_smooth_tensor_grid(grid_a, grid_b, nx, ny, smooth_iterations)

    inv_w = 1.0 / site_width if site_width > 0 else 0
    inv_h = 1.0 / site_height if site_height > 0 else 0
    nx1 = nx - 1
    ny1 = ny - 1

    def smoothed_fn(x, y):
        xi = x * inv_w * nx1
        yi = y * inv_h * ny1
        i0 = max(0, min(nx - 2, int(xi)))
        j0 = max(0, min(ny - 2, int(yi)))
        u = xi - i0
        v = yi - j0
        omu, omv = 1 - u, 1 - v
        a = omu * omv * grid_a[j0][i0] + omu * v * grid_a[j0+1][i0] + u * omv * grid_a[j0][i0+1] + u * v * grid_a[j0+1][i0+1]
        b = omu * omv * grid_b[j0][i0] + omu * v * grid_b[j0+1][i0] + u * omv * grid_b[j0][i0+1] + u * v * grid_b[j0+1][i0+1]
        return _tensor_to_eigenvectors(a, b) or (1.0, 0.0, 0.0, 1.0)

    return smoothed_fn


def sample_tensor_field_grid(site_width, site_height, basis, centers,
                             blend_factor=0.5, grid_step=25,
                             boundary=None, boundary_decay=150, boundary_blend=0.5,
                             height_gradient_fn=None, height_blend=0.5,
                             brush_strokes=None, brush_decay=80,
                             perlin_rotation_scale=0.005, perlin_rotation_strength=0):
    """
    在场地内均匀采样张量场，返回 (x, y, ux, uy, vx, vy) 列表。
    使用缓存的 design elements 加速。
    """
    tensor_fn = create_tensor_field_fn(
        basis, centers, blend_factor,
        boundary=boundary, boundary_decay=boundary_decay, boundary_blend=boundary_blend,
        height_gradient_fn=height_gradient_fn, height_blend=height_blend,
        brush_strokes=brush_strokes, brush_decay=brush_decay,
        perlin_rotation_scale=perlin_rotation_scale,
        perlin_rotation_strength=perlin_rotation_strength,
    )
    samples = []
    half_step = grid_step * 0.5
    x = half_step
    while x < site_width:
        y = half_step
        while y < site_height:
            ux, uy, vx, vy = tensor_fn(x, y)
            samples.append((x, y, ux, uy, vx, vy))
            y += grid_step
        x += grid_step
    return samples


def _centroid(centers):
    """多中心时取质心"""
    centers = _normalize_centers(centers)
    n = len(centers)
    cx = sum(p[0] for p in centers) / n
    cy = sum(p[1] for p in centers) / n
    return cx, cy


def generate_streets_from_tensor_field(site_width, site_height, basis, centers,
                                       blend_factor=0.5, line_spacing=40, pos_count=10, neg_count=10,
                                       cross_spacing=80,
                                       boundary=None, boundary_decay=150, boundary_blend=0.5,
                                       height_gradient_fn=None, height_blend=0.5):
    """
    从张量场生成街道网络线，返回与 offset 引擎兼容的格式。
    centers: list of (x,y) 或 (center_x, center_y)，多中心时用质心
    Returns: (lines, xs, ys) - lines 为纵向线列表，xs/ys 为中线用于自适应横街
    """

    center_x, center_y = _centroid(centers)

    lines = []
    for side in range(2):
        count = pos_count if side == 1 else neg_count
        start_i = 1 if side == 0 else 0
        for i in range(start_i, count + 1):
            offset_dist = (-i if side == 0 else i) * line_spacing
            line_pts = []
            for ti in range(T_COUNT):
                t = ti * T_STEP
                if basis == BASIS_GRID:
                    x = t * site_width
                    y = center_y + offset_dist
                elif basis == BASIS_RADIAL:
                    angle_spacing = 0.015
                    angle = offset_dist * angle_spacing
                    r = (0.05 + t * 0.95) * min(site_width, site_height) * 0.55
                    x = center_x + r * math.cos(angle)
                    y = center_y + r * math.sin(angle)
                elif basis == BASIS_BOUNDARY and boundary:
                    x = t * site_width
                    y = center_y + offset_dist
                elif basis in (BASIS_HEIGHT, BASIS_HEIGHT_BLEND):
                    x = t * site_width
                    y = center_y + offset_dist
                else:
                    x = t * site_width
                    y = center_y + offset_dist
                line_pts.append({"x": x, "y": y, "t": t, "offset": offset_dist})
            lines.append(line_pts)

    xs, ys = [], []
    for ti in range(T_COUNT):
        t = ti * T_STEP
        if basis == BASIS_GRID:
            xs.append(t * site_width)
            ys.append(center_y)
        else:
            xs.append(center_x + t * site_width * 0.5)
            ys.append(center_y)
    return lines, xs, ys

# --- hyperstreamline.py ---
"""
Hyperstreamline - 从张量场追踪主/副超流线
Major: 沿 u 方向积分
Minor: 沿 v 方向积分
停止条件: 边界、最大步数、最大长度、奇点（方向突变）
"""

import math


def _get_direction(tensor_fn, x, y, use_major, prev_dx, prev_dy):
    """获取与前一方向一致的单位方向。prev_dx, prev_dy 为 None 时取正向。"""
    ux, uy, vx, vy = tensor_fn(x, y)
    dx, dy = (ux, uy) if use_major else (vx, vy)
    L = math.sqrt(dx * dx + dy * dy) or 1e-10
    dx, dy = dx / L, dy / L
    if prev_dx is not None and (prev_dx * dx + prev_dy * dy) < 0:
        dx, dy = -dx, -dy
    return dx, dy


def _rk4_step(tensor_fn, x, y, use_major, prev_dx, prev_dy, dt):
    """RK4 单步，保持方向一致性"""
    def dir_at(px, py):
        return _get_direction(tensor_fn, px, py, use_major, None, None)

    d1x, d1y = _get_direction(tensor_fn, x, y, use_major, prev_dx, prev_dy)
    k1x, k1y = d1x * dt, d1y * dt

    d2x, d2y = dir_at(x + 0.5 * k1x, y + 0.5 * k1y)
    if prev_dx is not None and (d2x * prev_dx + d2y * prev_dy) < 0:
        d2x, d2y = -d2x, -d2y
    k2x, k2y = d2x * dt, d2y * dt

    d3x, d3y = dir_at(x + 0.5 * k2x, y + 0.5 * k2y)
    if prev_dx is not None and (d3x * prev_dx + d3y * prev_dy) < 0:
        d3x, d3y = -d3x, -d3y
    k3x, k3y = d3x * dt, d3y * dt

    d4x, d4y = dir_at(x + k3x, y + k3y)
    if prev_dx is not None and (d4x * prev_dx + d4y * prev_dy) < 0:
        d4x, d4y = -d4x, -d4y
    k4x, k4y = d4x * dt, d4y * dt

    return x + (k1x + 2 * k2x + 2 * k3x + k4x) / 6, y + (k1y + 2 * k2y + 2 * k3y + k4y) / 6


def integrate_hyperstreamline(
    tensor_fn,
    x0, y0,
    use_major=True,
    bidirectional=True,
    step_size=2.0,
    max_steps=500,
    max_length=None,
    bounds=None,
    angle_threshold=0.3,
):
    """
    从 (x0, y0) 追踪一条超流线。

    Args:
        tensor_fn: (x, y) -> (ux, uy, vx, vy)
        use_major: True=主超流线(沿u), False=副超流线(沿v)
        bidirectional: 是否双向积分
        step_size: 积分步长
        max_steps: 单方向最大步数
        max_length: 单方向最大长度，None 表示不限制
        bounds: (xmin, ymin, xmax, ymax)，超出则停止
        angle_threshold: 方向突变阈值，dot < angle_threshold 时停止（0.3≈72°，更宽松以延长流线）

    Returns:
        list of {"x", "y", "t"} 按积分顺序
    """
    def _integrate_one_dir(x0, y0, sign):
        pts = []
        x, y = x0, y0
        prev_dx, prev_dy = None, None
        pts.append({"x": x, "y": y, "t": 0})
        total_len = 0.0

        for i in range(max_steps - 1):
            dx, dy = _get_direction(tensor_fn, x, y, use_major, prev_dx, prev_dy)
            if sign < 0:
                dx, dy = -dx, -dy
            x_new, y_new = _rk4_step(tensor_fn, x, y, use_major, prev_dx, prev_dy, sign * step_size)
            dx_new, dy_new = _get_direction(tensor_fn, x_new, y_new, use_major, dx, dy)
            if sign < 0:
                dx_new, dy_new = -dx_new, -dy_new
            dot = dx * dx_new + dy * dy_new
            if dot < angle_threshold:
                break
            seg_len = math.sqrt((x_new - x) ** 2 + (y_new - y) ** 2)
            total_len += seg_len
            if max_length is not None and total_len > max_length:
                break
            if bounds:
                xmin, ymin, xmax, ymax = bounds
                if x_new < xmin or x_new > xmax or y_new < ymin or y_new > ymax:
                    break
            pts.append({"x": x_new, "y": y_new, "t": sign * (i + 1) * step_size})
            x, y = x_new, y_new
            prev_dx, prev_dy = dx_new, dy_new
        return pts

    if bidirectional:
        fwd = _integrate_one_dir(x0, y0, 1)
        bwd = _integrate_one_dir(x0, y0, -1)
        if len(bwd) > 1:
            bwd = bwd[1:]
        bwd.reverse()
        for i, p in enumerate(bwd):
            p["t"] = -(len(bwd) - i) * step_size
        return bwd + fwd
    return _integrate_one_dir(x0, y0, 1)


def integrate_hyperstreamlines_from_seeds(
    tensor_fn,
    seed_points,
    use_major=True,
    bidirectional=True,
    step_size=2.0,
    max_steps=500,
    max_length=None,
    bounds=None,
    angle_threshold=0.5,
):
    """
    从多个种子点追踪超流线。
    seed_points: [(x, y), ...]
    Returns: [line1, line2, ...] 每条 line 为 [{"x","y","t"}, ...]
    """
    lines = []
    for x0, y0 in seed_points:
        pts = integrate_hyperstreamline(
            tensor_fn, x0, y0,
            use_major=use_major,
            bidirectional=bidirectional,
            step_size=step_size,
            max_steps=max_steps,
            max_length=max_length,
            bounds=bounds,
            angle_threshold=angle_threshold,
        )
        lines.append(pts)
    return lines

# --- boundary_field.py ---
"""
Boundary Field - 从 river mask / 曲线提取边界，构造沿边界的局部张量
"""

import math



def extract_boundary_from_image(photo_image, site_width, site_height, river_threshold=200):
    """
    从 river mask 图像提取边界点。
    photo_image: tkinter.PhotoImage，白色/亮色=河流
    Returns: list of (x, y, tx, ty) 或 []（无 PIL 时仅支持 GIF）
    """
    try:
        w, h = photo_image.width(), photo_image.height()
    except Exception:
        return []
    if w < 2 or h < 2:
        return []
    # 缩放坐标到 site
    scale_x = site_width / max(w - 1, 1)
    scale_y = site_height / max(h - 1, 1)
    boundary_pts = []
    for py in range(h):
        for px in range(w):
            try:
                rgb = photo_image.get(px, py)
            except Exception:
                continue
            if isinstance(rgb, str):
                rgb = (int(rgb[1:3], 16), int(rgb[3:5], 16), int(rgb[5:7], 16))
            elif isinstance(rgb, (list, tuple)) and len(rgb) >= 3:
                rgb = tuple(rgb[:3])
            else:
                continue
            bright = sum(rgb) / 3 if isinstance(rgb, (tuple, list)) else 0
            is_river = bright >= river_threshold
            if not is_river:
                continue
            # 检查邻域是否有非河流 -> 边界点
            for dy, dx in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                nx, ny = px + dx, py + dy
                if 0 <= nx < w and 0 <= ny < h:
                    try:
                        nrgb = photo_image.get(nx, ny)
                    except Exception:
                        continue
                    if isinstance(nrgb, str):
                        nrgb = (int(nrgb[1:3], 16), int(nrgb[3:5], 16), int(nrgb[5:7], 16))
                    nbright = sum(nrgb[:3]) / 3 if isinstance(nrgb, (tuple, list)) else 0
                    if nbright < river_threshold:
                        x = px * scale_x
                        y = py * scale_y
                        tx = -dy
                        ty = dx
                        boundary_pts.append((x, y, tx, ty))
                        break
    return boundary_pts


def extract_boundary_from_curve(points, num_samples=120):
    """
    从曲线点提取边界：采样点 + 每点切向。
    Returns: list of (x, y, tx, ty) - 位置与单位切向
    """
    if not points or len(points) < 2:
        return []
    sampled = sample_curve(points, num_samples=num_samples)
    if len(sampled) < 2:
        return []
    boundary = []
    n = len(sampled)
    for i in range(n):
        x, y = sampled[i][0], sampled[i][1]
        i0 = (i - 1) % n
        i1 = (i + 1) % n
        dx = sampled[i1][0] - sampled[i0][0]
        dy = sampled[i1][1] - sampled[i0][1]
        L = math.sqrt(dx * dx + dy * dy) or 1e-10
        tx, ty = dx / L, dy / L
        boundary.append((x, y, tx, ty))
    return boundary


def nearest_on_boundary(x, y, boundary):
    """
    求 (x,y) 到边界的最短距离点。
    Returns: (bx, by, tx, ty, dist) 或 None
    """
    if not boundary:
        return None
    best = None
    best_d2 = 1e30
    n = len(boundary)
    for i in range(n):
        bx, by, tx, ty = boundary[i][0], boundary[i][1], boundary[i][2], boundary[i][3]
        # 点到线段的距离（近似为点到采样点）
        d2 = (x - bx) ** 2 + (y - by) ** 2
        if d2 < best_d2:
            best_d2 = d2
            best = (bx, by, tx, ty, math.sqrt(d2))
    return best


def boundary_tensor_at(x, y, boundary, decay=150):
    """
    在 (x,y) 处根据边界计算张量：u=边界切向，v=法向。
    距离衰减：越近边界影响越强。
    """
    if not boundary:
        return None
    nn = nearest_on_boundary(x, y, boundary)
    if nn is None:
        return None
    bx, by, tx, ty, dist = nn
    # 衰减权重：exp(-d^2 / decay^2)
    w = math.exp(-(dist * dist) / (decay * decay))
    if w < 0.01:
        return None  # 太远，不贡献
    ux, uy = tx, ty
    vx, vy = -ty, tx  # 法向
    return (ux, uy, vx, vy, w)

# --- height_field.py ---
"""
Height Field - 从灰度高程图生成张量场
输入灰度高程图 -> 求梯度 -> 生成 tensor basis (u=等高线方向, v=梯度方向)
"""

import math

# 尝试导入 PIL，用于 PNG/JPG；无则仅支持 GIF (PhotoImage)
try:
    from PIL import Image
    _HAS_PIL = True
except ImportError:
    _HAS_PIL = False


def _normalize(ux, uy):
    L = math.sqrt(ux * ux + uy * uy) or 1e-10
    return ux / L, uy / L


def _orthogonal(ux, uy):
    return _normalize(-uy, ux)


def _photoimage_to_grid(photo_image, site_width, site_height):
    """从 tkinter PhotoImage 提取灰度高程网格。支持 GIF。"""
    try:
        w, h = photo_image.width(), photo_image.height()
    except Exception:
        return None, 0, 0
    if w < 2 or h < 2:
        return None, 0, 0
    grid = []
    for py in range(h):
        row = []
        for px in range(w):
            try:
                rgb = photo_image.get(px, py)
            except Exception:
                row.append(0)
                continue
            if isinstance(rgb, str):
                rgb = (int(rgb[1:3], 16), int(rgb[3:5], 16), int(rgb[5:7], 16))
            elif isinstance(rgb, (list, tuple)) and len(rgb) >= 3:
                rgb = tuple(rgb[:3])
            else:
                row.append(0)
                continue
            bright = sum(rgb) / 3
            row.append(bright)
        grid.append(row)
    return grid, w, h


def _pil_to_grid(pil_image, site_width, site_height):
    """从 PIL Image 提取灰度高程网格。"""
    if pil_image is None:
        return None, 0, 0
    gray = pil_image.convert("L")
    w, h = gray.size
    if w < 2 or h < 2:
        return None, 0, 0
    grid = []
    px_data = gray.load()
    for py in range(h):
        row = []
        for px in range(w):
            row.append(float(px_data[px, py]))
        grid.append(row)
    return grid, w, h


def build_height_field_from_image(image, site_width, site_height, use_pil=True):
    """
    从图像构建高度场。
    image: tkinter.PhotoImage (GIF) 或 PIL.Image (PNG/JPG)
    Returns: (height_at, gradient_at) 或 (None, None) 若失败
    """
    grid = None
    img_w, img_h = 0, 0

    if use_pil and _HAS_PIL and hasattr(image, "size"):
        # PIL Image
        grid, img_w, img_h = _pil_to_grid(image, site_width, site_height)
    elif hasattr(image, "width") and hasattr(image, "get"):
        # tkinter PhotoImage
        grid, img_w, img_h = _photoimage_to_grid(image, site_width, site_height)
    else:
        return None, None

    if grid is None or img_w < 2 or img_h < 2:
        return None, None

    scale_x = (img_w - 1) / max(site_width, 1)
    scale_y = (img_h - 1) / max(site_height, 1)

    def _px_py(x, y):
        px = max(0, min(img_w - 1, x * scale_x))
        py = max(0, min(img_h - 1, y * scale_y))
        return int(px), int(py)

    def height_at(x, y):
        px, py = _px_py(x, y)
        return grid[py][px]

    def gradient_at(x, y):
        """中心差分求梯度 (gx, gy)。梯度指向高程增加方向。"""
        px, py = _px_py(x, y)
        # 边界用单边差分
        if px <= 0:
            gx = grid[py][min(1, img_w - 1)] - grid[py][0]
        elif px >= img_w - 1:
            gx = grid[py][img_w - 1] - grid[py][max(0, img_w - 2)]
        else:
            gx = (grid[py][px + 1] - grid[py][px - 1]) / 2.0

        if py <= 0:
            gy = grid[min(1, img_h - 1)][px] - grid[0][px]
        elif py >= img_h - 1:
            gy = grid[img_h - 1][px] - grid[max(0, img_h - 2)][px]
        else:
            gy = (grid[py + 1][px] - grid[py - 1][px]) / 2.0

        # 图像 y 向下，逻辑 y 向上，取反
        return (gx, -gy)

    return height_at, gradient_at


def height_tensor_at(x, y, gradient_at_fn):
    """
    在 (x,y) 处根据梯度生成张量基底。
    u = 等高线方向（垂直于梯度）
    v = 梯度方向（上坡）
    Returns: (ux, uy, vx, vy) 或 None（平坦区回退到 grid）
    """
    gx, gy = gradient_at_fn(x, y)
    L = math.sqrt(gx * gx + gy * gy)
    if L < 1e-6:
        return None  # 平坦区
    # u = 等高线方向 = 垂直于梯度（逆时针旋转90°）
    ux, uy = _normalize(-gy, gx)
    vx, vy = _orthogonal(ux, uy)  # v = 梯度方向
    return ux, uy, vx, vy

# --- street_from_hyperstreamlines.py ---
"""
论文街道生成：从超流线交点构建图 G=(V,E)
- 主/副超流线交替追踪（减少悬空边）
- 交点作为节点 V，超流线段作为边 E
- 支持二阶段：主路 → 分区 → 次路
"""

import math


def _intersect_segments(a1, a2, b1, b2, tol=1e-6):
    """
    线段 a1-a2 与 b1-b2 求交。
    返回 (x, y) 或 None
    """
    x1, y1 = a1[0], a1[1]
    x2, y2 = a2[0], a2[1]
    x3, y3 = b1[0], b1[1]
    x4, y4 = b2[0], b2[1]
    denom = (x1 - x2) * (y3 - y4) - (y1 - y2) * (x3 - x4)
    if abs(denom) < tol:
        return None
    t = ((x1 - x3) * (y3 - y4) - (y1 - y3) * (x3 - x4)) / denom
    u = -((x1 - x2) * (y1 - y3) - (y1 - y2) * (x1 - x3)) / denom
    if 0 <= t <= 1 and 0 <= u <= 1:
        return (x1 + t * (x2 - x1), y1 + t * (y2 - y1))
    return None


def _line_to_segments(line):
    """超流线点列表转为线段列表"""
    segs = []
    for i in range(len(line) - 1):
        p1 = (line[i]["x"], line[i]["y"])
        p2 = (line[i + 1]["x"], line[i + 1]["y"])
        segs.append((p1, p2))
    return segs


def _find_intersections(major_lines, minor_lines):
    """主/副超流线交点"""
    intersections = []
    for mj_line in major_lines:
        mj_segs = _line_to_segments(mj_line)
        for mn_line in minor_lines:
            mn_segs = _line_to_segments(mn_line)
            for s1 in mj_segs:
                for s2 in mn_segs:
                    pt = _intersect_segments(s1[0], s1[1], s2[0], s2[1])
                    if pt:
                        intersections.append(pt)
    return intersections


def _expand_seeds_for_coverage(site_width, site_height, seed_points, min_seeds=9):
    """
    当种子点过少（1-2个）时，在场地上生成均匀分布的多种子，避免街道团成一团。
    单中心或双中心时，超流线易汇聚，需多种子分散覆盖。
    """
    if seed_points and len(seed_points) >= min_seeds:
        return seed_points
    # 在场地上生成 3x3 或 4x4 网格种子，带边距
    margin = 0.1
    n = 4 if site_width * site_height > 400000 else 3  # 大场地用 4x4
    seeds = []
    for i in range(n):
        for j in range(n):
            t = (i + 1) / (n + 1)
            s = (j + 1) / (n + 1)
            x = margin * site_width + (1 - 2 * margin) * site_width * t
            y = margin * site_height + (1 - 2 * margin) * site_height * s
            seeds.append((x, y))
    return seeds


def _merge_near_points(points, tol=2.0):
    """合并距离小于 tol 的点，用平方距离避免 sqrt"""
    if not points:
        return []
    tol_sq = tol * tol
    out = [points[0]]
    for p in points[1:]:
        merged = False
        px, py = p[0], p[1]
        for i, q in enumerate(out):
            dx = px - q[0]
            dy = py - q[1]
            if dx * dx + dy * dy < tol_sq:
                out[i] = ((px + q[0]) * 0.5, (py + q[1]) * 0.5)
                merged = True
                break
        if not merged:
            out.append(p)
    return out


def interleaved_hyperstreamlines(
    tensor_fn,
    seed_points,
    d_sep=65,
    step_size=2.0,
    max_steps=500,
    max_length=None,
    bounds=None,
    angle_threshold=0.3,
):
    """
    论文 6.1 交替追踪：主→副→主→副...，减少悬空边。
    从种子开始，沿主方向追踪一条，在 d_sep 处取新种子沿副方向追踪，如此交替。
    Returns: (major_lines, minor_lines)
    """
    def _trace_one(x0, y0, use_major):
        pts = integrate_hyperstreamline(
            tensor_fn, x0, y0,
            use_major=use_major,
            bidirectional=True,
            step_size=step_size,
            max_steps=max_steps,
            max_length=max_length,
            bounds=bounds,
            angle_threshold=angle_threshold,
        )
        return pts

    major_lines = []
    minor_lines = []
    used_seeds = set()

    def _seed_key(x, y):
        return (round(x / 2), round(y / 2))

    queue = [(x, y, True) for x, y in seed_points]
    while queue:
        x0, y0, do_major = queue.pop(0)
        key = _seed_key(x0, y0)
        if key in used_seeds:
            continue
        used_seeds.add(key)

        line = _trace_one(x0, y0, do_major)
        if len(line) < 2:
            continue

        if do_major:
            major_lines.append(line)
        else:
            minor_lines.append(line)

        # 沿超流线每 d_sep 距离添加新种子（论文：交替追踪）
        total = 0
        next_seed_dist = d_sep
        for i in range(len(line) - 1):
            dx = line[i + 1]["x"] - line[i]["x"]
            dy = line[i + 1]["y"] - line[i]["y"]
            seg_len = math.sqrt(dx * dx + dy * dy)
            while total + seg_len >= next_seed_dist:
                t = (next_seed_dist - total) / seg_len if seg_len > 0 else 0
                nx = line[i]["x"] + t * dx
                ny = line[i]["y"] + t * dy
                queue.append((nx, ny, not do_major))
                next_seed_dist += d_sep
            total += seg_len

    return major_lines, minor_lines


def _find_nearest_idx(pt, vertices, tol=5):
    """找最近顶点索引，用平方距离"""
    best = -1
    best_d2 = tol * tol
    ptx, pty = pt[0], pt[1]
    for i, v in enumerate(vertices):
        d2 = (ptx - v[0]) ** 2 + (pty - v[1]) ** 2
        if d2 < best_d2:
            best_d2 = d2
            best = i
    return best


def hyperstreamlines_to_street_graph(
    major_lines,
    minor_lines,
    bounds=None,
):
    """
    从主/副超流线构建街道图 G=(V,E)。
    Returns: {"vertices": [(x,y),...], "edges": [(i,j),...], "edge_pts": [[(x,y),...],...]}
    """

    if bounds:
        xmin, ymin, xmax, ymax = bounds
    else:
        xmin = ymin = 0
        xmax = ymax = 1e9

    # 收集交点
    intersections = []
    for mj in major_lines:
        mj_segs = _line_to_segments(mj)
        for mn in minor_lines:
            mn_segs = _line_to_segments(mn)
            for s1 in mj_segs:
                for s2 in mn_segs:
                    pt = _intersect_segments(s1[0], s1[1], s2[0], s2[1])
                    if pt and xmin <= pt[0] <= xmax and ymin <= pt[1] <= ymax:
                        intersections.append(pt)

    # 收集所有线段端点
    all_pts = list(intersections)
    for line in major_lines + minor_lines:
        for p in line:
            pt = (p["x"], p["y"])
            if xmin <= pt[0] <= xmax and ymin <= pt[1] <= ymax:
                all_pts.append(pt)

    vertices = _merge_near_points(all_pts, tol=3.0)
    if not vertices:
        return {"vertices": [], "edges": [], "edge_pts": []}

    edges = []
    edge_pts = []

    for line in major_lines + minor_lines:
        for i in range(len(line) - 1):
            p1 = (line[i]["x"], line[i]["y"])
            p2 = (line[i + 1]["x"], line[i + 1]["y"])
            clipped = clip_segment_to_rect(p1, p2, xmin, ymin, xmax, ymax)
            if clipped and len(clipped) == 2:
                a, b = clipped[0], clipped[1]
                d = math.sqrt((b[0] - a[0]) ** 2 + (b[1] - a[1]) ** 2)
                if d > 2:
                    ia = _find_nearest_idx(a, vertices, 8)
                    ib = _find_nearest_idx(b, vertices, 8)
                    if ia >= 0 and ib >= 0 and ia != ib:
                        edges.append((ia, ib))
                        edge_pts.append([a, b])
                    else:
                        edge_pts.append([a, b])

    return {"vertices": vertices, "edges": edges, "edge_pts": edge_pts}


def generate_streets_from_hyperstreamlines(
    tensor_fn,
    site_width,
    site_height,
    seed_points=None,
    d_sep=65,
    step_size=2.0,
    max_length=None,
    angle_threshold=0.3,
):
    """
    论文式街道生成：超流线交替追踪 → 交点图。
    Returns: (lines, xs, ys) 兼容旧格式，lines 为每条超流线的点列表
    """

    bounds = (0, 0, site_width, site_height)
    if not seed_points:
        seed_points = [(site_width / 2, site_height / 2)]
    seed_points = _expand_seeds_for_coverage(site_width, site_height, seed_points)

    major_lines, minor_lines = interleaved_hyperstreamlines(
        tensor_fn, seed_points,
        d_sep=d_sep,
        step_size=step_size,
        max_length=max_length,
        bounds=bounds,
        angle_threshold=angle_threshold,
    )

    xmin, ymin, xmax, ymax = bounds
    lines = []
    for line in major_lines + minor_lines:
        line_pts = []
        for i, p in enumerate(line):
            x, y = p["x"], p["y"]
            if xmin <= x <= xmax and ymin <= y <= ymax:
                t = i / max(len(line) - 1, 1)
                line_pts.append({"x": x, "y": y, "t": t, "offset": 0})
        if len(line_pts) >= 2:
            lines.append(line_pts)

    cx = site_width / 2
    cy = site_height / 2
    return lines, [cx], [cy]


def partition_by_major_roads(major_lines, site_width, site_height):
    """
    论文 6.2：主路将区域划分成子区域，用于次路生成。
    major_lines: 主超流线列表
    Returns: list of (polygon, center) 每个子区域的近似多边形和中心
    """
    # 简化：用主路网格划分，返回网格单元
    # 完整实现需要多边形裁剪，这里返回整个场地作为单区域
    return [([(0, 0), (site_width, 0), (site_width, site_height), (0, site_height)],
             (site_width / 2, site_height / 2))]


def generate_minor_roads_in_region(
    tensor_fn,
    region_polygon,
    region_center,
    d_sep=40,
    step_size=2.0,
    bounds=None,
    angle_threshold=0.3,
):
    """
    在子区域内生成次路。可用不同的张量场（局部）。
    """
    if bounds:
        xmin, ymin, xmax, ymax = bounds
        w, h = xmax - xmin, ymax - ymin
        seeds = _expand_seeds_for_coverage(w, h, [region_center], min_seeds=4)
        seeds = [(xmin + x, ymin + y) for x, y in seeds]
    else:
        seeds = [region_center]
    major_lines, minor_lines = interleaved_hyperstreamlines(
        tensor_fn, seeds,
        d_sep=d_sep,
        step_size=step_size,
        bounds=bounds,
        angle_threshold=angle_threshold,
    )
    return major_lines + minor_lines


def two_stage_street_generation(
    tensor_fn,
    site_width,
    site_height,
    seed_points=None,
    major_d_sep=65,
    minor_d_sep=40,
    step_size=2.0,
    angle_threshold=0.3,
):
    """
    论文 6.1+6.2 二阶段：主路 → 分区 → 次路。
    Returns: (lines, xs, ys) 兼容格式
    """
    bounds = (0, 0, site_width, site_height)
    if not seed_points:
        seed_points = [(site_width / 2, site_height / 2)]
    seed_points = _expand_seeds_for_coverage(site_width, site_height, seed_points)

    major_lines, _ = interleaved_hyperstreamlines(
        tensor_fn, seed_points,
        d_sep=major_d_sep,
        step_size=step_size,
        bounds=bounds,
        angle_threshold=angle_threshold,
    )

    regions = partition_by_major_roads(major_lines, site_width, site_height)
    minor_lines = []
    for poly, center in regions:
        lines = generate_minor_roads_in_region(
            tensor_fn, poly, center,
            d_sep=minor_d_sep,
            step_size=step_size,
            bounds=bounds,
            angle_threshold=angle_threshold,
        )
        minor_lines.extend(lines)

    xmin, ymin, xmax, ymax = bounds
    lines = []
    for line in major_lines + minor_lines:
        line_pts = []
        for i, p in enumerate(line):
            x, y = p["x"], p["y"]
            if xmin <= x <= xmax and ymin <= y <= ymax:
                t = i / max(len(line) - 1, 1)
                line_pts.append({"x": x, "y": y, "t": t, "offset": 0})
        if len(line_pts) >= 2:
            lines.append(line_pts)

    return lines, [site_width / 2], [site_height / 2]

